// OpenCL kernel for mixbench - translated from OpenMP implementation

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 enabled
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 enabled
#endif

__kernel void benchmark_func(class_T seed, __global class_T* data) {
    size_t global_id = get_global_id(0);

    class_T f = seed;
    class_T sum = (class_T)0;

    #if ELEMENTS_PER_THREAD > 0
    #define EPT ELEMENTS_PER_THREAD
    #else
    #define EPT 1
    #endif

    #if FUSION_DEGREE > 0
    #define FD FUSION_DEGREE
    #else
    #define FD 1
    #endif

    #if COMPUTE_ITERATIONS > 0
    #define CI COMPUTE_ITERATIONS
    #else
    #define CI 1
    #endif

    #ifdef BLOCK_STRIDED
    size_t stride = blockdim;
    #else
    size_t stride = 1;
    #endif

    size_t base_idx = global_id * EPT * FD * stride;

    for (int fd = 0; fd < FD; fd++) {
        for (int ei = 0; ei < EPT; ei++) {
            size_t idx = base_idx + (fd * EPT + ei) * stride;
            class_T t = data[idx];

            for (int j = 0; j < CI; j++) {
                t = t * t + f;
            }

            sum += t;
        }
    }

    data[global_id] = sum;
}

// OpenCL kernel for mixbench GPU benchmark
// Translated from OpenMP CPU implementation

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 enable
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef BLOCK_STRIDED
#define WORKITEM_IDX (get_group_id(0) * blockdim + get_local_id(0))
#define GRID_STRIDE (get_num_groups(0) * blockdim)
#else
#define WORKITEM_IDX get_global_id(0)
#define GRID_STRIDE get_global_size(0)
#endif

__attribute__((reqd_work_group_size(blockdim)))
void benchmark_func(class_T seed, class_T* data) {
    class_T sum = 0;
    class_T f = seed;

    size_t total_elements = GRID_STRIDE * ELEMENTS_PER_THREAD * FUSION_DEGREE;

    for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
        size_t base_idx = WORKITEM_IDX * ELEMENTS_PER_THREAD + 
                          fusion * GRID_STRIDE * ELEMENTS_PER_THREAD;

        for (size_t elem = 0; elem < ELEMENTS_PER_THREAD; elem++) {
            size_t idx = base_idx + elem;
            if (idx < total_elements) {
                class_T t = data[idx];
                for (size_t iter = 0; iter < COMPUTE_ITERATIONS; iter++) {
                    t = t * t + f;
                }
                sum += t;
            }
        }
    }

    data[WORKITEM_IDX] = sum;
}
